SELECT p.place_id, p.title, p.addr1, p.first_image1, p.category_code1, p.category_code2, COUNT(DISTINCT pl.user_id) AS like_count, EXISTS ( SELECT 1 FROM place_likes WHERE place_id = p.place_id AND user_id = #{userId} ) AS liked, AVG(r.rating) AS avg_rating, COUNT(DISTINCT r.review_id) AS review_count FROM places p LEFT JOIN place_likes pl ON p.place_id = pl.place_id LEFT JOIN reviews r ON p.place_id = r.place_id
AND p.area_code = #{req.areaCode}
AND p.district_code = #{req.districtCode}
AND p.category_code1 = #{req.category1}
AND p.category_code2 = #{req.category2}
AND p.title LIKE CONCAT('%', #{req.keyword}, '%')
AND p.addr1 IS NOT NULL AND p.addr1 != ''
GROUP BY p.place_id ORDER BY like_count DESC, p.place_id LIMIT #{req.limitSize} OFFSET #{req.offset}

SELECT COUNT(*) > 0
FROM place_likes
WHERE place_id = #{placeId} AND user_id = #{userId}

SELECT COUNT(*)
FROM place_likes
WHERE place_id = #{placeId}
